(function() {
  var input = document.getElementById("searchInput");
  var results = document.getElementById("searchResults");
  if (!input || !results || !window.SEARCH_MOVIES) {
    return;
  }

  var params = new URLSearchParams(window.location.search);
  var initial = params.get("q") || "";
  input.value = initial;

  function html(value) {
    return String(value).replace(/[&<>"']/g, function(ch) {
      return {
        "&": "&amp;",
        "<": "&lt;",
        ">": "&gt;",
        "\"": "&quot;",
        "'": "&#39;"
      }[ch];
    });
  }

  function render(list) {
    if (!list.length) {
      results.innerHTML = '<div class="search-empty">没有找到匹配影片。</div>';
      return;
    }
    results.innerHTML = list.slice(0, 120).map(function(item) {
      return '<article class="movie-card">' +
        '<a class="poster" href="./' + html(item.url) + '">' +
        '<img src="./' + html(item.cover) + '" alt="' + html(item.title) + '" loading="lazy">' +
        '<span class="poster-mask"><span class="play-dot"></span></span>' +
        '<span class="year-badge">' + html(item.year) + '</span>' +
        '</a>' +
        '<div class="movie-info">' +
        '<h2><a href="./' + html(item.url) + '">' + html(item.title) + '</a></h2>' +
        '<p class="meta-line">' + html(item.region) + ' · ' + html(item.type) + ' · ' + html(item.genre) + '</p>' +
        '<p class="desc-line">' + html(item.oneLine) + '</p>' +
        '</div>' +
        '</article>';
    }).join("");
  }

  function run() {
    var query = input.value.trim().toLowerCase();
    if (!query) {
      render(window.SEARCH_MOVIES.slice(0, 48));
      return;
    }
    var matched = window.SEARCH_MOVIES.filter(function(item) {
      var bag = [item.title, item.year, item.region, item.type, item.genre, item.oneLine].concat(item.tags || []).join(" ").toLowerCase();
      return bag.indexOf(query) !== -1;
    });
    render(matched);
  }

  input.addEventListener("input", run);
  run();
}());
